ll gcd(ll a, ll b) {
    while (a > 0) {
        ll temp = b % a;
        b = a;
        a = temp;
    }
    return b;
}

ll lcm(ll a, ll b) {
    return a / gcd(a, b) * b;
}

ll ceildiv(ll n, ll k) {
    ll t = n / k;
    if (n % k == 0) return t;
    return t + 1;
}

ll pw(ll a, ll b) {
    ll r = 1;
    while (b) {
        if (b & 1) r *= a;
        a *= a;
        b >>= 1;
    }
    return r;
}

ll modpw(ll a, ll b, ll mod) {
    ll r = 1 % mod;
    a %= mod;
    while (b) {
        if (b & 1) r = r * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return r;
}

const int mod = 998244353;

void solve() {
    int n;
    cin >> n;

    vector<pll> d(n + 1);
    vll fac(n + 1);
    fac[0] = 1;

    map<ll, ll> a, b;
    map<pll , ll> ab;

    for (ll i = 1; i <= n; ++i) {
        cin >> d[i].first >> d[i].second;
        fac[i] = i * fac[i - 1] % mod;
        ++a[d[i].first];
        ++b[d[i].second];
        ++ab[d[i]];
    }

    sort(d.begin() + 1, d.end());

    ll ans = fac[n];

    ll tmp = 1;
    for (auto &p : a) {
        tmp = tmp * fac[p.second] % mod;
    }
    ans = (ans - tmp + mod) % mod;

    tmp = 1;
    for (auto &p : b) {
        tmp = tmp * fac[p.second] % mod;
    }
    ans = (ans - tmp + mod) % mod;

    tmp = 1;
    for (auto &p : ab) {
        tmp = tmp * fac[p.second] % mod;
    }
    for (ll i = 1; i < n; ++i) {
        if (d[i + 1].second < d[i].second) {
            tmp = 0;
            break;
        }
    }
    ans = (ans + tmp) % mod;

    cout << ans << '\n';
}

