#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;

int mul(int a, int b) {
    return (long long)a * b % MOD;
}

int add(int a, int b) {
    return (a + b) % MOD;
}

int sub(int a, int b) {
    return (a - b + MOD) % MOD;
}

void add_inplace(vector<int>& v, int i, int x) {
    v[i] = add(v[i], x);
}

void sub_inplace(vector<int>& v, int i, int x) {
    v[i] = sub(v[i], x);
}

int power(int base, int exp) {
    int result = 1;
    while (exp > 0) {
        if (exp & 1)
            result = mul(result, base);
        base = mul(base, base);
        exp >>= 1;
    }
    return result;
}

int mod_inverse(int a) {
    return power(a, MOD - 2);
}

vector<int> fact, inv_fact;

void precompute_factorials(int max_n) {
    fact.resize(max_n + 1);
    inv_fact.resize(max_n + 1);
    fact[0] = 1;
    for (int i = 1; i <= max_n; ++i) {
        fact[i] = mul(fact[i - 1], i);
        inv_fact[i] = mod_inverse(fact[i]);
    }
}

int binomial_coefficient(int n, int k) {
    if (k > n)
        return 0;
    return mul(mul(fact[n], inv_fact[k]), inv_fact[n - k]);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<pair<int, int>> s(n);
    for (int i = 0; i < n; ++i) {
        cin >> s[i].first >> s[i].second;
    }

    precompute_factorials(n);

    // Sort indices based on first elements
    vector<int> idx(n);
    iota(idx.begin(), idx.end(), 0);
    sort(idx.begin(), idx.end(), [&](int i, int j) {
        return s[i].first < s[j].first;
    });

    // Inversion counting for second elements in the sorted order
    vector<int> pos(n);
    vector<int> cnt(n);
    for (int i = 0; i < n; ++i) {
        pos[idx[i]] = i;
    }

    int inv_count = 0;
    for (int i = 0; i < n; ++i) {
        int p = pos[i];
        int c = cnt[p];
        inv_count = add(inv_count, mul(p - c, binomial_coefficient(n - 1 - c, p - c)));
        add_inplace(cnt, p, 1);
    }

    // Total permutations minus invalid ones
    int total_permutations = fact[n];
    int invalid_permutations = add(total_permutations, sub(total_permutations, inv_count));

    cout << invalid_permutations << '\n';

    return 0;
}

