    string currentCategory = getCategory(x);
    int maxMod = -1;
    string maxCategory = "";

    for (int i = 0; i <= 2; ++i) {
        int newMod = (x + i) % 4;
        if (newMod > maxMod) {
            maxMod = newMod;
            maxCategory = getCategory(newMod);
