#include <iostream>
#include <vector>
#include <unordered_map>
#include <algorithm>
using namespace std;

void solve(int n, vector<int>& p) {
    int min_swaps = n * n; // Upper bound
    int best_i = -1, best_j = -1;

    // Precompute prefix sums of frequencies
    vector<unordered_map<int, int>> pref(n + 1);
    for (int i = 1; i <= n; ++i) {
        pref[i] = pref[i - 1];
        pref[i][p[i - 1]]++;
    }

    // Precompute suffix sums of frequencies
    vector<unordered_map<int, int>> suff(n + 1);
    for (int i = n - 1; i >= 0; --i) {
        suff[i] = suff[i + 1];
        suff[i][p[i]]++;
    }

    // Iterate over all pairs (i, j)
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (i == j) continue;

            // Create new array after swap
            vector<int> q = p;
            swap(q[i - 1], q[j - 1]);

            // Recompute subarray counts for the new array
            unordered_map<int, int> freq;
            int perm_count = 0;
            for (int k = 1; k <= n; ++k) {
                freq[q[k - 1]]++;
                if (freq[q[k - 1]] > k) {
                    // Remove elements from the left to make it a permutation
                    while (pref[k][q[k - 1]] > 1) {
                        pref[k][q[k - 1]]--;
                        k--;
                    }
                    perm_count++;
                }
            }

            // Update best swap if found a better one
            if (perm_count < min_swaps) {
                min_swaps = perm_count;
                best_i = i;
                best_j = j;
            }
        }
    }

    cout << best_i << " " << best_j << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            cin >> p[i];
        }
        solve(n, p);
    }

    return 0;
}

