#include <iostream>
#include <iomanip>
using namespace std;

double solve(long long k, long long d, long long t) {
    double time = 0;
    bool stove_on = true;

    while (true) {
        double current_interval = min(d, k);

        if (stove_on) {
            if (current_interval >= k) {
                stove_on = false;
                time += t;
                continue;
            } else {
                time += t * current_interval / k;
            }
        } else {
            time += 2 * t * current_interval / k;
        }

        time += d;

        if (stove_on && time > 2 * t) {
            return time;
        }

        stove_on = !stove_on;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cout << fixed << setprecision(9);

    long long k, d, t;
    cin >> k >> d >> t;

    cout << solve(k, d, t) << endl;

    return 0;
}

