int solve(vector<vector<long long>>& grid) {
    int n = grid[0].size();
    vector<long long> prefix(n, 0);

    // Compute prefix sums for each column
    for (const auto& row : grid) {
        for (int j = 0; j < n; ++j) {
            prefix[j] += row[j];
        }
    }

    unordered_map<long long, vector<int>> sum_positions;
    sum_positions[0].push_back(-1); // To handle zero-sum from start

    long long total_sum = accumulate(prefix.begin(), prefix.end(), 0LL);
    unordered_map<long long, int> current_sums;
    current_sums[total_sum] = 0;

    int max_rectangles = 0;

    for (int i = 0; i < n; ++i) {
        long long diff = total_sum - prefix[i];

        if (current_sums.count(diff)) {
            max_rectangles++;
        }

        current_sums[prefix[i]]++;
    }

    return max_rectangles;
}

