int count_triangles(const vector<int>& lengths) {
    int n = lengths.size();
    sort(lengths.begin(), lengths.end());

    int count = 0;
    for (int i = 0; i < n - 2; ++i) {
        int left = i + 1;
        int right = n - 1;
        while (left < right) {
            if (lengths[i] + lengths[left] > lengths[right]) {
                count += right - left;
                --right;
            } else {
                ++left;
            }
        }
    }
    return count;
}

