using namespace std;

bool isValid(const vector<int>& a, const vector<int>& b, int i, int j) {
    unordered_set<long long> sums_a;
    unordered_set<long long> sums_b;

    for (int k = 0; k < i; ++k) {
        long long sum_a = accumulate(a.begin(), a.begin() + k + 1, 0LL);
        long long sum_b = accumulate(b.begin(), b.begin() + k + 1, 0LL);
        if (sums_a.count(sum_a)) return false;
        if (sums_b.count(sum_b)) return false;
        sums_a.insert(sum_a);
        sums_b.insert(sum_b);
    }

    long long sum_a = accumulate(a.begin(), a.begin() + i + 1, 0LL);
    long long sum_b = accumulate(b.begin(), b.begin() + i + 1, 0LL);
    return !sums_a.count(sum_a) && !sums_b.count(sum_b);
}

void backtrack(vector<int>& a, vector<int>& b, int i) {
    if (i == a.size()) {
        cout << "1";
        for (int num : b) {
            cout << " " << num;
        }
        cout << endl;
        exit(0);
    }

    for (int j = 0; j < a.size(); ++j) {
        if (b[j] != 0) continue;

        if (!isValid(a, b, i, j)) continue;

        b[j] = a[i];
        backtrack(a, b, i + 1);
        b[j] = 0;
    }
}

