    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<int> a(n);
    for (int& x : a) cin >> x;

    vector<int> b(n, 0);
    backtrack(a, b, 0);

    cout << "-1" << endl;
    return 0;
}

