    ios::sync_with_stdio(false); cin.tie(nullptr);

    cin >> n >> t >> q;
    p.assign(n, 0); l.assign(n, 0);
    for (int i = 0; i < n; ++i) cin >> p[i];
    for (int i = 0; i < n; ++i) cin >> l[i];

    init();

    while (!pq.empty()) {
        auto [currSum, dist] = pq.front(); pq.pop();
        cout << currSum << '\n';

        for (int i = 0; i < n; ++i) {
            if (dist[i] < l[i]) { // Can still add more tickets
                addTicket(i);
            }
            if (dist[i] > 0) { // Can still remove tickets
                removeTicket(i);
            }
        }
    }

    return 0;
}
