    }

    for (int b = 1; b < B; ++b) {
        pre[b].assign(n + 1, 0);
        for (int a = n; a >= 1; --a) {
            ll val = w[a];
            if (a + b <= n) val += pre[b][a + b];
            pre[b][a] = val;
