struct Fen {
    vector<int> value;
    Fen(int n) : value(n, 0) {}
    ll get(int fro, int to) {
        return get1(to) - get1(fro - 1);
    }
    ll get1(int to) {
        to = min(to, (int)value.size() - 1);
        ll result = 0;
        while (to >= 0) {
            result += value[to];
            to = (to & (to + 1)) - 1;
        }
        return result;
    }
    void add(int at, int val) {
        while (at < (int)value.size()) {
            value[at] += val;
            at = at | (at + 1);
        }
    }
};

void solve() {
    int n, k;
    cin >> n >> k;
    k = min(k, n - k);
    vll res(n);
    ll ans = 1;
    int cur = 0;
    Fen fen(n);
    for (int iteration = 0; iteration < n; ++iteration) {
        int nxt = (cur + k) % n;
        ll here = 0;
        if (cur < nxt) {
            here = fen.get(cur + 1, nxt - 1);
        } else {
            here = fen.get(0, nxt - 1) + fen.get(cur + 1, n - 1);
        }
        fen.add(cur, 1);
        fen.add(nxt, 1);
        cur = nxt;
        ans += here + 1;
        res[iteration] = ans;
    }
    for (int i = 0; i < n; ++i) {
        if (i) cout << ' ';
