void multiply(vector<vector<int>>& A, const vector<vector<int>>& B) {
    int n = A.size();
    vector<vector<int>> C(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int k = 0; k < n; ++k) {
                C[i][j] = (C[i][j] + static_cast<long long>(A[i][k]) * B[k][j]) % MOD;
            }
        }
    }
    A = C;
}

void power(vector<vector<int>>& A, long long m) {
    int n = A.size();
    vector<vector<int>> res(n, vector<int>(n));
    for (int i = 0; i < n; ++i) res[i][i] = 1;
    while (m > 0) {
        if (m & 1) multiply(res, A);
        multiply(A, A);
        m >>= 1;
    }
    A = res;
}

