#include <climits>
using namespace std;

const int MAXN = 2000;
int dist[MAXN][MAXN];

void preprocess(int n, int m, vector<vector<int>>& a) {
    // Initialize distance grid with infinity
    for (int i = 0; i <= n; ++i)
        for (int j = 0; j <= m; ++j)
            dist[i][j] = INT_MAX;

    // Traverse from top-left to bottom-right
    for (int i = 0; i <= n; ++i) {
        for (int j = 0; j <= m; ++j) {
            if (a[i][j] == 1) {
                dist[i][j] = 0;
                if (i > 0) dist[i][j] = min(dist[i][j], dist[i-1][j] + 1);
                if (j > 0) dist[i][j] = min(dist[i][j], dist[i][j-1] + 1);
            }
        }
        for (int j = m; j >= 0; --j) {
            if (a[i][j] == 1) continue;
            if (j < m) dist[i][j] = min(dist[i][j], dist[i][j+1] + 1);
        }
    }

    // Traverse from bottom-right to top-left
    for (int i = n; i >= 0; --i) {
        for (int j = m; j >= 0; --j) {
            if (a[i][j] == 1) continue;
            if (i < n) dist[i][j] = min(dist[i][j], dist[i+1][j] + 1);
        }
        for (int j = 0; j <= m; ++j) {
            if (a[i][j] == 1) continue;
            if (j > 0) dist[i][j] = min(dist[i][j], dist[i][j-1] + 1);
        }
    }
}

long long solve(int n, int m, vector<vector<int>>& a) {
    preprocess(n, m, a);

    long long total = 0;
    for (int i = 0; i <= n; ++i)
        for (int j = 0; j <= m; ++j)
            total += static_cast<long long>(dist[i][j]) * dist[i][j];

    return total;
}

