    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<vector<int>> a(n + 1, vector<int>(m + 1));

    for (int i = 0; i <= n; ++i)
        for (int j = 0; j <= m; ++j)
            cin >> a[i][j];

    cout << solve(n, m, a) << endl;

    return 0;
}

