#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int dfs(const vector<int>& a, int pos, int n, vector<vector<int>>& memo) {
    if (pos == n)
        return 1;
    if (memo[pos][pos] != -1)
        return memo[pos][pos];

    int paths = 0;
    for (int j = 1; j <= a[pos]; ++j) {
        if (pos + j >= n)
            break;
        paths += dfs(a, pos + j, n, memo);
    }
    memo[pos][pos] = paths;
    return paths;
}

int minChanges(vector<int>& a, int n) {
    vector<vector<int>> memo(n, vector<int>(n, -1));
    int initialPaths = dfs(a, 0, n, memo);

    if (initialPaths == 1)
        return 0;

    int ans = n;
    for (int i = 0; i < n; ++i) {
        vector<int> modified = a;
        modified[i] = 0;
        vector<vector<int>> newMemo(n, vector<int>(n, -1));
        int newPaths = dfs(modified, 0, n, newMemo);

        if (newPaths == 1)
            ans = min(ans, 1);
        else if (newPaths > 1)
            ans = min(ans, 1 + minChanges(modified, n));
    }

    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> a(n);
        for (int i = 0; i < n; ++i)
            cin >> a[i];

        cout << minChanges(a, n) << '\n';
    }

    return 0;
}

