bool topoSort(vi &order, int n) {
    queue<int> q;
    for (int i = 1; i <= n; ++i) {
        if (indegree[i] == 0) q.push(i);
    }

    while (!q.empty()) {
        int u = q.front(); q.pop();
        order.push_back(u);

        for (int v : adj[u]) {
            if (--indegree[v] == 0) q.push(v);
        }
    }

    return order.size() == n;
}

void solve(int n, int m) {
    for (int i = 0; i <= n; ++i) {
        adj[i].clear();
        indegree[i] = 0;
    }

    for (int i = 0; i < m; ++i) {
        int x, y; cin >> x >> y;
        adj[x].push_back(y);
        indegree[y]++;
    }

    vi order;
    if (!topoSort(order, n)) {
        cout << "No solution\n";
        return;
    }

    vi closedSpots;
    unordered_set<int> seen;

    for (int u : order) {
        for (int v : adj[u]) {
            if (seen.count(v)) {
                // Cycle detected, add node u to closed spots
                closedSpots.push_back(u);
                break;
            }
            seen.insert(v);
        }
        seen.clear();
    }

    int k = min((int)closedSpots.size(), (int)(4 * n / 7));
    cout << k << "\n";
