const int MAX_D = 1000000;
const int MAX_C = 1000000;
const long long INF = 1LL << 60;

struct Spell {
    int d, c;
};

struct State {
    int d, k;
    bool operator<(const State& other) const {
        return d != other.d ? d < other.d : k < other.k;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int q, m;
    cin >> q >> m;

    vector<Spell> spells;
    unordered_map<int, unordered_map<int, bool>> dp;

    while (q--) {
        int ki, ai, bi;
        cin >> ki >> ai >> bi;

        if (ki == 1) {
            int dx = (ai + spells.size()) % MAX_D + 1;
            int cy = (bi + spells.size()) % MAX_C + 1;
            spells.push_back({dx, cy});
        } else {
            int tx = (ai + spells.size()) % MAX_D + 1;
            int hx = (bi + spells.size()) % MAX_C + 1;

            dp.clear();
            dp[0][0] = true;

            for (auto& s : spells) {
                auto old_dp = dp;
                for (auto [d, k] : old_dp) {
                    if (!old_dp[d][k]) continue;
                    int new_d = d + s.d * k;
                    int new_k = k + s.c * k;
                    if (new_d <= hx && new_k <= tx) {
                        dp[new_d][new_k] = true;
                    }
                }
            }

            if (dp[hx].find(tx) != dp[hx].end()) cout << "YES\n";
            else cout << "NO\n";
        }
    }

    return 0;
}

