    char letters[3] = {'A', 'B', 'C'};
    bool found[3] = {false};

    // Mark letters present in the specified row and column
    for (int i = 0; i < 3; ++i) {
        if (row1[i] != '?' && row1[i] != '.')
            found[row1[i] - 'A'] = true;
        if (row2[i] != '?' && row2[i] != '.')
            found[row2[i] - 'A'] = true;
        if (row3[i] != '?' && row3[i] != '.')
            found[row3[i] - 'A'] = true;
    }

    // The missing letter is the one not marked as found
    for (int i = 0; i < 3; ++i) {
        if (!found[i])
