    ll r = 1;
    while (b) {
        if (b & 1) r *= a;
        a *= a;
        b >>= 1;
    }
    return r;
}

ll modpw(ll a, ll b, ll mod) {
    ll r = 1 % mod;
    a %= mod;
    while (b) {
        if (b & 1) r = r * a % mod;
        a = a * a % mod;
        b >>= 1;
    }
    return r;
}

void solve() {
    int n, m, k;
    cin >> n >> m >> k;
    vector<vll> a(n, vll(m));
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            cin >> a[i][j];

    int maxP = n + m + 5;
    int maxQ = n + m + 5;
    int offset = m + 2;
    vector<vll> B(maxP, vll(maxQ, 0));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int p = i + j;
            int q = i - j + offset;
            B[p][q] = a[i][j];
        }
    }
    vector<vll> PS(maxP, vll(maxQ, 0));
    for (int i = 0; i < maxP; ++i) {
        for (int j = 0; j < maxQ; ++j) {
            ll val = B[i][j];
            if (i > 0) val += PS[i-1][j];
            if (j > 0) val += PS[i][j-1];
            if (i > 0 && j > 0) val -= PS[i-1][j-1];
            PS[i][j] = val;
        }
    }
    auto getPS = [&](int x, int y) -> ll {
        if (x < 0 || y < 0) return 0;
        if (x >= maxP) x = maxP - 1;
        if (y >= maxQ) y = maxQ - 1;
        return PS[x][y];
    };
    auto squareSum = [&](int cx, int cy, int r) -> ll {
        int x1 = cx - r, y1 = cy - r;
        int x2 = cx + r, y2 = cy + r;
        return getPS(x2, y2) - getPS(x1-1, y2) - getPS(x2, y1-1) + getPS(x1-1, y1-1);
    };

    ll best = -1;
    int bestA = -1, bestB = -1;
    for (int x = k-1; x <= n - k; ++x) {
        for (int y = k-1; y <= m - k; ++y) {
            int P0 = x + y;
            int Q0 = x - y + offset;
            ll f = 0;
            for (int r = 0; r < k; ++r) {
                f += squareSum(P0, Q0, r);
            }
            if (f > best) {
                best = f;
                bestA = x + 1;
                bestB = y + 1;
            }
        }
    }
    cout << bestA << ' ' << bestB << '\n';
}

int main() {
    fastio;
    solve();
    return 0;
}

