long long abs(long long x) {
    return x < 0 ? -x : x;
}

long long calculate_f(const vector<vector<int>>& grid, int a, int b, int n, int m, int k) {
    long long result = 0;
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            int dist = abs(i - a) + abs(j - b);
            if (dist <= k) {
                result += static_cast<long long>(grid[i-1][j-1]) * (k - dist + 1);
            }
        }
    }
    return result;
}

void solve() {
    int n, m, k;
    cin >> n >> m >> k;

