using namespace std;

const int MOD = 1e9 + 7;
const int MAXN = 5005;

int a[MAXN];
long long dp[MAXN][MAXN];
long long dpd[MAXN][MAXN];

void solve(int n) {
    // Read input
    cin >> n;
    for (int i = 1; i < n; ++i) {
        cin >> a[i];
    }

    // Initialize DP arrays
    for (int i = 0; i <= n; ++i) {
        fill(dp[i], dp[i] + MAXN, 0);
        fill(dpd[i], dpd[i] + MAXN, 0);
    }
    dp[0][0] = 1; // Root node at depth 0, 0 steps up

    // Fill DP array for moving upwards
    for (int i = 1; i <= n; ++i) {
        for (int j = 0; j <= i; ++j) {
            dp[i][j] = (dp[i][j] + dp[i-1][j]) % MOD;
            if (j > 0) {
                dp[i][j] = (dp[i][j] + dp[i-1][j-1]) % MOD;
            }
        }
    }

    // Fill DP array for moving downwards
    for (int i = n-1; i >= 0; --i) {
        for (int j = 0; j <= n-i; ++j) {
            dpd[i][j] = (dpd[i][j] + dpd[i+1][j+1] * a[i+1]) % MOD;
        }
    }

    // Calculate fk
    vector<long long> result(2*n-2, 0);
    for (int k = 1; k < 2*n-1; ++k) {
        for (int j = 0; j <= k; ++j) {
            result[k-1] = (result[k-1] + dp[j][k-j] * dpd[n-k+j][j]) % MOD;
        }
    }

    // Output result
    for (int k = 0; k < 2*n-2; ++k) {
        cout << result[k] << " ";
    }
    cout << endl;
}

