const ll MXN = 2e5 + 5;
const ll mod = 1e9 + 7;

ll f[MXN], invf[MXN];

ll modpw(ll a, ll b) {
    a %= mod;
    ll res = 1;
    while (b) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

ll nck(ll n, ll k) {
    n = max(n, 0LL);
    if (min(n, k) < 0 || k > n) return 0;
    return (f[n] * ((invf[k] * invf[n - k]) % mod)) % mod;
}

void init() {
    f[0] = 1;
    for (ll i = 1; i < MXN; i++) f[i] = (f[i - 1] * i) % mod;
    for (ll i = 0; i < MXN; i++) invf[i] = modpw(f[i], mod - 2);
}

void solve() {
    ll n, res = 0;
    cin >> n;
    for (ll i = 1; i <= 2 * n + 1; i++) {
        for (ll b1 = 1; b1 <= min(n + 1, i); b1++) {
            if (i > n) {
                ll x = (b1 - 1) - (i - n - 1);
                if (x < 0) continue;
                ll y = n - x;
                if (y != b1 - 1) continue;
                res = (res + (nck(n, x) * i)) % mod;
