#include <iostream>
#include <vector>
using namespace std;

const int MOD = 1000000009;

int find(vector<int>& parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void merge(vector<int>& parent, vector<int>& rank, int x, int y) {
    x = find(parent, x);
    y = find(parent, y);
    if (x == y) return;
    if (rank[x] > rank[y]) {
        parent[y] = x;
    } else if (rank[x] < rank[y]) {
        parent[x] = y;
    } else {
        parent[y] = x;
        rank[x]++;
    }
}

long long modPow(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

long long comb(int n, int k, long long mod) {
    if (k > n) return 0;
    long long num = 1, den = 1;
    for (int i = 1; i <= k; ++i) {
        num = (num * (n - i + 1)) % mod;
        den = (den * i) % mod;
    }
    return (num * modPow(den, mod - 2, mod)) % mod;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<int> parent(n + 1), rank(n + 1, 0);
    for (int i = 1; i <= n; ++i) parent[i] = i;

    vector<long long> ans(m);
    long long totalWays = 1;
    int currCycles = 0;

    for (int i = 0; i < m; ++i) {
        int u, v;
        cin >> u >> v;
        int rootU = find(parent, u);
        int rootV = find(parent, v);
        if (rootU == rootV) {
            // Same component, forming a cycle
            currCycles++;
            ans[i] = (totalWays * (currCycles + 1)) % MOD;
            totalWays = ((totalWays * (currCycles + 1)) % MOD + 1) % MOD;
        } else {
            // Different components, merging them
            merge(parent, rank, u, v);
            ans[i] = totalWays;
            totalWays = (totalWays * (currCycles + 1)) % MOD;
            currCycles--;
        }
    }

    for (int i = 0; i < m; ++i) {
        cout << ans[i] << '\n';
    }

    return 0;
}

