int min_cost_path(int n, int k, vector<vector<int>>& adj) {
    const int INF = INT_MAX;
    vector<vector<int>> dp(n, vector<int>(1 << (n * n), INF));
    dp[0][0] = 0;

    // Enumerate all paths of length k starting and ending at vertex 1
    for (int mask = 0; mask < (1 << (n * n)); ++mask) {
        for (int i = 0; i < n; ++i) {
            if (dp[i][mask] == INF)
                continue;
            for (int j = 0; j < n; ++j) {
                if (i != j && adj[i][j] > 0 && ((mask >> (i*n + j)) & 1) == 0) {
                    int new_mask = mask | (1 << (i*n + j));
                    dp[j][new_mask] = min(dp[j][new_mask], dp[i][mask] + adj[i][j]);
                }
            }
        }
    }

    int ans = INF;
    for (int mask = 0; mask < (1 << (n * n)); ++mask) {
        if (dp[0][mask] != INF && __builtin_popcount(mask) == k) {
            ans = min(ans, dp[0][mask]);
        }
    }

    return ans;
}

