    }
    for (int i = 0; i < n; ++i) {
        cin >> b[i];
        b[i + n] = b[i];
    }

    vll pref(2 * n + 1, 0);
    for (int i = 0; i < 2 * n; ++i) {
        pref[i + 1] = pref[i] + a[i];
    }

    vector<int> nxt(2 * n);
    vll cost(2 * n);
    vll len(2 * n);

    for (int i = 0; i < 2 * n; ++i) {
        if (b[i] == 2) {
            nxt[i] = i + 1;
            cost[i] = 2 * a[i];
            len[i] = a[i];
        } else {
            int cnt = 0;
            int j = i + 1;
            while (j < 2 * n && b[j] == 2) {
                ++cnt;
                ++j;
            }
            if (cnt == 0) {
                nxt[i] = i + 1;
                cost[i] = a[i];
                len[i] = a[i];
            } else {
                int lo = i, hi = i + cnt;
                int best = i;
                while (lo <= hi) {
                    int mid = (lo + hi) / 2;
                    if (pref[mid + 1] - pref[i] <= k) {
                        best = mid;
                        lo = mid + 1;
                    } else {
                        hi = mid - 1;
                    }
                }
                ll sum = pref[best + 1] - pref[i];
                if (sum <= k) {
                    nxt[i] = best + 1;
                    cost[i] = sum;
                    len[i] = sum;
                } else {
                    nxt[i] = best + 1;
                    cost[i] = k + 2 * (sum - k);
                    len[i] = sum;
                }
            }
        }
    }

    vector<vector<int>> up(LOG, vector<int>(2 * n));
    vector<vll> up_cost(LOG, vll(2 * n));
    vector<vll> up_len(LOG, vll(2 * n));

    for (int i = 0; i < 2 * n; ++i) {
        up[0][i] = nxt[i];
        up_cost[0][i] = cost[i];
        up_len[0][i] = len[i];
    }

    for (int p = 1; p < LOG; ++p) {
        for (int i = 0; i < 2 * n; ++i) {
            int mid = up[p - 1][i];
            up[p][i] = up[p - 1][mid];
            up_cost[p][i] = up_cost[p - 1][i] + up_cost[p - 1][mid];
            up_len[p][i] = up_len[p - 1][i] + up_len[p - 1][mid];
        }
    }

    for (int i = 0; i < n; ++i) {
        int cur = i;
        ll total_cost = 0;
        ll total_len = 0;
        for (int p = LOG - 1; p >= 0; --p) {
            if (total_len + up_len[p][cur] < pref[i + n] - pref[i]) {
                total_cost += up_cost[p][cur];
                total_len += up_len[p][cur];
                cur = up[p][cur];
            }
        }
        if (total_len < pref[i + n] - pref[i]) {
            ll rem = pref[i + n] - pref[i] - total_len;
            if (b[cur] == 2) {
                total_cost += 2 * rem;
            } else {
                total_cost += rem;
            }
        }
        cout << total_cost << " \n"[i == n - 1];
    }
}

