int minTurns(long long x) {
    // Normalize the absolute value of x modulo 360
    int abs_x = abs(x);
    int mod_360 = abs_x % 360;

    // Find the nearest multiple of 90
    int nearest_multiple = ((mod_360 + 45) / 90) * 90;

    // Calculate the difference
    int diff = nearest_multiple - mod_360;

    // If diff is greater than 45, it's cheaper to go the other way
    if (diff > 45) {
        diff = 90 - diff;
    }

    return diff / 90;
}

