    cin >> s >> x1 >> x2;
    int t1, t2;
    cin >> t1 >> t2;
    int p, d;
    cin >> p >> d;

    // Calculate walking time
    int walk_time = abs(x2 - x1) * t2;

    // Initialize answer with walking time
    int min_time = walk_time;

    // Check all possible boarding points
    for (double board_pos = 0; board_pos <= s; board_pos += 0.01) {
        double dist_to_board = abs(board_pos - x1);
        double time_to_board = dist_to_board / t2;

        // Distance the tram travels in that time
        double tram_dist = time_to_board * t1;
        double new_tram_pos = p + d * tram_dist;

        // Check if the tram reaches the boarding point before Igor
        if ((board_pos == p && d > 0) || (board_pos == p && d < 0)) {
            continue;
        }

        // Calculate remaining distance after boarding
        double remaining_dist = abs(new_tram_pos - x2);
        double tram_travel_time = remaining_dist / t1;

        // Total time including waiting and tram ride
        double total_time = time_to_board + tram_travel_time;

        // Update minimum time
        if (total_time < min_time) {
            min_time = total_time;
        }
    }

    cout << min_time << endl;
    return 0;
}

