#include <iostream>
#include <vector>
using namespace std;

const int MOD = 1000000007;
long long factorial[31];
long long inverse_factorial[31];

void precompute() {
    factorial[0] = 1;
    for (int i = 1; i <= 30; ++i) {
        factorial[i] = factorial[i - 1] * i % MOD;
    }
    inverse_factorial[30] = pow(factorial[30], MOD - 2, MOD);
    for (int i = 29; i >= 0; --i) {
        inverse_factorial[i] = inverse_factorial[i + 1] * (i + 1) % MOD;
    }
}

long long C(int n, int k) {
    if (k > n) return 0;
    return factorial[n] * inverse_factorial[k] % MOD * inverse_factorial[n - k] % MOD;
}

int solve(int n, int m, int t) {
    precompute();
    long long result = 0;
    for (int b = max(4, t - m); b <= min(n, t - 1); ++b) {
        long long ways_boys = C(n, b);
        long long ways_girls = C(m, t - b);
        result = (result + ways_boys * ways_girls % MOD) % MOD;
    }
    return static_cast<int>(result);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m, t;
    cin >> n >> m >> t;

    cout << solve(n, m, t) << endl;

    return 0;
}

