using namespace std;

struct Participant {
    vector<int> times;
    int points = 0;
    int penalty = 0;
};

void simulate(vector<vector<int>>& times, int h) {
    int n = times.size();
    int m = times[0].size();

    // Sort each participant's times
    for (auto& p : times) {
        sort(p.begin(), p.end());
    }

    vector<Participant> participants;
    for (int i = 0; i < n; ++i) {
        Participant p;
        p.times = times[i];
        participants.push_back(p);
    }

    // Simulate solving problems
    for (auto& p : participants) {
        int t = 0;
        for (int j = 0; j < m; ++j) {
            if (t + p.times[j] <= h) {
                t += p.times[j];
                ++p.points;
                p.penalty += t;
            } else {
                break;
            }
        }
    }

    // Sort participants by points and then penalty
    sort(participants.begin(), participants.end(),
         [](const Participant& a, const Participant& b) {
             return a.points > b.points || (a.points == b.points && a.penalty < b.penalty);
         });

    // Find Rudolf's rank
    int rudolf_index = 0;
    for (int i = 0; i < n; ++i) {
        if (participants[i].points == participants[rudolf_index].points &&
            participants[i].penalty == participants[rudolf_index].penalty) {
            continue;
        }
        if (participants[i].points > participants[rudolf_index].points ||
            (participants[i].points == participants[rudolf_index].points && participants[i].penalty < participants[rudolf_index].penalty)) {
            rudolf_index = i;
        }
    }

    cout << rudolf_index + 1 << endl;
}

