#define ll long long

struct Cell {
    ll pos;
    ll treasure;
    bool operator<(const Cell& other) const {
        if (treasure == other.treasure) return pos < other.pos;
        return treasure > other.treasure;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    ll h, n, m, k;
    cin >> h >> n >> m >> k;

    vector<Cell> treasures(n);
    for (int i = 0; i < n; ++i) {
        cin >> treasures[i].pos >> treasures[i].treasure;
    }

    set<ll> reachable = {1};
    while (!reachable.empty()) {
        ll cur = *reachable.begin();
        reachable.erase(reachable.begin());
        if (cur <= h) reachable.insert(cur + k);
    }

    for (auto& t : treasures) {
        reachable.insert(t.pos);
    }

    vector<Cell> active_cells;
    for (ll pos : reachable) {
        active_cells.push_back({pos, 0});
    }

    int op_type;
    while (m--) {
        cin >> op_type;
        if (op_type == 1) {
            ll x;
            cin >> x;
            auto new_reachable = reachable;
            for (ll r : reachable) {
                new_reachable.insert(r + x);
            }
            reachable = new_reachable;

            // Update active cells
            active_cells.clear();
            for (ll pos : reachable) {
                active_cells.push_back({pos, 0});
            }
        } else if (op_type == 2) {
            ll x, y;
            cin >> x >> y;
            treasures[x - 1].treasure -= y;
        } else {
            if (active_cells.empty()) {
                cout << 0 << '\n';
                continue;
            }

            sort(active_cells.begin(), active_cells.end());
            Cell best = active_cells.front();

            // Remove the best cell
            reachable.erase(best.pos);
            active_cells.erase(active_cells.begin());

            cout << best.treasure << '\n';
        }
    }

    return 0;
}

