    global_set.insert(x);
    for (int k = 1; k <= MAX_K; ++k) {
        if (x % k == 0) {
            auto& vec = divisible_sets[k];
            auto it = lower_bound(vec.begin(), vec.end(), x);
            if (it != vec.end()) {
                vec.erase(it);
            }
        }
    }
