void process_remove(long long x) {
    global_set.erase(global_set.find(x));
    for (int k = 1; k <= MAX_K; ++k) {
        if (x % k == 0) {
            auto& vec = divisible_sets[k];
            auto it = lower_bound(vec.begin(), vec.end(), x);
            if (it == vec.end() || *it != x) {
                vec.push_back(x);
            } else {
                vec.erase(it);
            }
        }
    }
}

