        val[idx] = new_val;
        seg[node].F = new_val;
        seg[node].S = 1;
    } else {
        int mid = (start + end) / 2;
        if(idx <= mid) update(node * 2, start, mid, idx, new_val);
        else update(node * 2 + 1, mid + 1, end, idx, new_val);
        int left_val = seg[node * 2].F;
        int left_cnt = seg[node * 2].S;
        int right_val = seg[node * 2 + 1].F;
        int right_cnt = seg[node * 2 + 1].S;
        if(left_cnt == left_val + 1 && left_val == right_val) {
            seg[node].F = left_val + 1;
            seg[node].S = left_cnt + right_cnt;
        } else {
            seg[node].F = left_val;
            seg[node].S = left_cnt;
        }
    }
}

int mex(vi &values) {
    vi count(MAXN, 0);
    for(int x : values) {
        if(x >= MAXN) continue;
        count[x]++;
    }
    for(int i = 0; i < MAXN; ++i) {
        if(count[i] == 0) return i;
    }
    return MAXN;
}

void dfs(int u, int par) {
    p[u] = par;
    vi vals;
    for(int v : adj[u]) {
        if(v != par) {
            dfs(v, u);
            vals.pb(val[v]);
        }
    }
    sort(vals.begin(), vals.end());
    val[u] = mex(vals);
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0);

    cin >> q;
    int root = 1;
    adj[root].pb(2);
    val[1] = 0;
    val[2] = 0;
    seg.resize(4 * MAXN);
    build(1, 1, MAXN);

    rep(i, 1, q) {
        int x;
        cin >> x;
        int new_idx = i + 1;
        adj[x].pb(new_idx);
        int new_val = 0;
        int cur = new_idx;
        while(cur != root) {
            int par = p[cur];
            auto [par_val, par_cnt] = query(1, 1, MAXN, 1, par);
            vi temp_vals = adj[par];
            temp_vals.erase(remove(temp_vals.begin(), temp_vals.end(), cur), temp_vals.end());
            int mx = 0;
            for(int v : temp_vals) mx = max(mx, val[v]);
            if(par_val > mx) {
                new_val = par_val;
            } else {
                new_val = par_val + 1;
            }
            update(1, 1, MAXN, cur, new_val);
            cur = par;
        }
        cout << accumulate(val + 1, val + new_idx + 1, 0LL) << '\n';
    }

    return 0;
}

