#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2e6 + 7;

int parent[MAXN], rank[MAXN];

void init(int n) {
    for (int i = 0; i <= n; ++i) {
        parent[i] = i;
        rank[i] = 0;
    }
}

int find(int u) {
    return parent[u] == u ? u : parent[u] = find(parent[u]);
}

bool unite(int u, int v) {
    u = find(u);
    v = find(v);
    if (u == v) return false;
    if (rank[u] > rank[v]) {
        parent[v] = u;
    } else {
        parent[u] = v;
        if (rank[u] == rank[v]) ++rank[v];
    }
    return true;
}

struct Coupon {
    int value, weight;
};

bool cmp(const Coupon &a, const Coupon &b) {
    return a.weight > b.weight;
}

long long maxPayable(vector<Coupon>& coupons, int n) {
    sort(coupons.begin(), coupons.end(), cmp);
    long long totalWeight = 0;
    init(MAXN);

    for (const auto& coupon : coupons) {
        if (unite(coupon.value, coupon.weight)) {
            totalWeight += coupon.weight;
        }
    }

    return totalWeight;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    vector<Coupon> coupons(m);
    for (int i = 0; i < m; ++i) {
        cin >> coupons[i].value >> coupons[i].weight;
    }

    cout << maxPayable(coupons, n) << endl;

    return 0;
}
